mapper.update:
UPDATE CHAT_ROOM
SET CHAT_RM_LAST_MSG = #{chatRmLastMsg}
WHERE CHAT_RM_NO = #{chatRmNo}

mapper.delete:
DELETE FROM CHAT
WHERE CHAT_RM_NO = #{chatRmNo}
  AND EMP_ID = #{empId}

mapper.select:
SELECT EMP_NM 
FROM EMPLOYEE 
WHERE EMP_ID = #{empId}

SELECT  A.CHAT_RM_NO,
        A.CHAT_RM_TTL,
        A.CHAT_RM_TYPE
FROM    CHAT_ROOM A
INNER JOIN CHAT B ON A.CHAT_RM_NO = B.CHAT_RM_NO
WHERE   B.EMP_ID = #{empId}
  AND   A.CHAT_RM_TYPE = #{chatRmType}
  AND   A.CHAT_RM_YN = 'Y'
  AND   A.CHAT_RM_TTL = #{chatRmTtl}

SELECT COUNT(*) 
FROM CHAT 
WHERE CHAT_RM_NO = #{chatRmNo}

mapper.update:
UPDATE CHAT_ROOM 
SET CHAT_RM_YN = #{chatRmYn},
    CHAT_RM_END_DT = #{chatRmEndDt, jdbcType=TIMESTAMP}
WHERE CHAT_RM_NO = #{chatRmNo}
